5	package software.amazon.smithy.model.shapes;
6	
7	import java.io.Serializable;
8	import java.util.Comparator;
9	import java.util.Map;
10	import software.amazon.smithy.model.FromSourceLocation;
11	import software.amazon.smithy.model.SourceLocation;
12	import software.amazon.smithy.model.node.Node;
13	import software.amazon.smithy.model.traits.TraitDefinition;
14	import software.amazon.smithy.utils.MapUtils;
15	
16	/**
17	 * Defines how shapes, traits, and metadata are sorted when serializing a model with {@link SmithyIdlModelSerializer}.
18	 */
19	public enum SmithyIdlComponentOrder {
20	    /**
21	     * Sort shapes, traits, and metadata alphabetically. Member order, however, is not sorted.
22	     */
23	    ALPHA_NUMERIC,
24	
25	    /**
26	     * Sort shapes, traits, and metadata by source location, persisting their original placement when parsed.
27	     */
28	    SOURCE_LOCATION,
29	
30	    /**
31	     * Reorganizes shapes based on a preferred ordering of shapes, and alphanumeric traits and metadata.
32	     *
33	     * <p>Shapes are ordered as follows:
34	     *
35	     * <ul>
36	     *     <li>Trait definitions</li>
37	     *     <li>Services</li>
38	     *     <li>Resources</li>
39	     *     <li>Operations</li>
40	     *     <li>Structures</li>
41	     *     <li>Unions</li>
42	     *     <li>Lists</li>
43	     *     <li>Maps</li>
44	     *     <li>Finally, alphabetically by shape type.</li>
45	     * </ul>
46	     */
47	    PREFERRED;
48	
49	    Comparator<Shape> shapeComparator() {
50	        return this == PREFERRED ? new PreferredShapeComparator() : toShapeIdComparator();
51	    }
52	
53	    <T extends FromSourceLocation & ToShapeId> Comparator<T> toShapeIdComparator() {
54	        switch (this) {
55	            case PREFERRED:
56	            case ALPHA_NUMERIC:
57	                return Comparator.comparing(ToShapeId::toShapeId);
58	            case SOURCE_LOCATION:
59	            default:
60	                return new SourceComparator<>();
61	        }
62	    }
63	
64	    Comparator<Map.Entry<String, Node>> metadataComparator() {
65	        switch (this) {
66	            case ALPHA_NUMERIC:
67	            case PREFERRED:
68	                return Map.Entry.comparingByKey();
69	            case SOURCE_LOCATION:
70	            default:
71	                return new MetadataComparator();
72	        }
73	    }
74	
75	    private static final class SourceComparator<T extends FromSourceLocation & ToShapeId>
76	            implements Comparator<T>, Serializable {
77	        @Override
78	        public int compare(T a, T b) {
79	            SourceLocation left = a.getSourceLocation();
80	            SourceLocation right = b.getSourceLocation();
81	            int comparison = left.compareTo(right);
82	            return comparison != 0 ? comparison : a.toShapeId().compareTo(b.toShapeId());
83	        }
84	    }
85	
86	    private static final class MetadataComparator implements Comparator<Map.Entry<String, Node>>, Serializable {
87	        @Override
88	        public int compare(Map.Entry<String, Node> a, Map.Entry<String, Node> b) {
89	            SourceLocation left = a.getValue().getSourceLocation();
90	            SourceLocation right = b.getValue().getSourceLocation();
91	            int comparison = left.compareTo(right);
92	            return comparison != 0 ? comparison : a.getKey().compareTo(b.getKey());
93	        }
94	    }
95	
96	    /**
97	     * Comparator used to sort shapes.
98	     */
99	    private static final class PreferredShapeComparator implements Comparator<Shape>, Serializable {
100	        private static final Map<ShapeType, Integer> PRIORITY = MapUtils.of(
101	                ShapeType.SERVICE,
102	                0,
103	                ShapeType.RESOURCE,
104	                1,
105	                ShapeType.OPERATION,
106	                2,
107	                ShapeType.STRUCTURE,
108	                3,
109	                ShapeType.UNION,
110	                4,
111	                ShapeType.LIST,
112	                5,
113	                ShapeType.SET,
114	                6,
115	                ShapeType.MAP,
116	                7);
117	
118	        @Override
119	        public int compare(Shape s1, Shape s2) {
120	            // Traits go first
121	            if (s1.hasTrait(TraitDefinition.ID) || s2.hasTrait(TraitDefinition.ID)) {
122	                if (!s1.hasTrait(TraitDefinition.ID)) {
123	                    return 1;
124	                }
125	                if (!s2.hasTrait(TraitDefinition.ID)) {
126	                    return -1;
127	                }
128	                // The other sorting rules don't matter for traits.
129	                return s1.compareTo(s2);
130	            }
131	            // If the shapes are the same type, just compare their shape ids.
132	            if (s1.getType().equals(s2.getType())) {
133	                return s1.compareTo(s2);
134	            }
135	            // If one shape is prioritized, compare by priority.
136	            if (PRIORITY.containsKey(s1.getType()) || PRIORITY.containsKey(s2.getType())) {
137	                // If only one shape is prioritized, that shape is "greater".
138	                if (!PRIORITY.containsKey(s1.getType())) {
139	                    return 1;
140	                }
141	                if (!PRIORITY.containsKey(s2.getType())) {
142	                    return -1;
143	                }
144	                return PRIORITY.get(s1.getType()) - PRIORITY.get(s2.getType());
145	            }
146	            return s1.compareTo(s2);
147	        }
148	    }
149	}
