1	/*
2	 * Copyright Amazon.com, Inc. or its affiliates. All Rights Reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	package software.amazon.smithy.model.shapes;
6	
7	import java.nio.file.Path;
8	import java.nio.file.Paths;
9	import java.util.ArrayList;
10	import java.util.Collection;
11	import java.util.Collections;
12	import java.util.Comparator;
13	import java.util.HashMap;
14	import java.util.HashSet;
15	import java.util.LinkedHashMap;
16	import java.util.List;
17	import java.util.Map;
18	import java.util.Objects;
19	import java.util.Optional;
20	import java.util.Set;
21	import java.util.function.Function;
22	import java.util.function.Predicate;
23	import java.util.regex.Pattern;
24	import java.util.stream.Collectors;
25	import software.amazon.smithy.model.Model;
26	import software.amazon.smithy.model.knowledge.OperationIndex;
27	import software.amazon.smithy.model.loader.Prelude;
28	import software.amazon.smithy.model.node.ArrayNode;
29	import software.amazon.smithy.model.node.BooleanNode;
30	import software.amazon.smithy.model.node.Node;
31	import software.amazon.smithy.model.node.NumberNode;
32	import software.amazon.smithy.model.node.ObjectNode;
33	import software.amazon.smithy.model.node.StringNode;
34	import software.amazon.smithy.model.traits.AnnotationTrait;
35	import software.amazon.smithy.model.traits.DefaultTrait;
36	import software.amazon.smithy.model.traits.DocumentationTrait;
37	import software.amazon.smithy.model.traits.EnumValueTrait;
38	import software.amazon.smithy.model.traits.IdRefTrait;
39	import software.amazon.smithy.model.traits.InputTrait;
40	import software.amazon.smithy.model.traits.OutputTrait;
41	import software.amazon.smithy.model.traits.Trait;
42	import software.amazon.smithy.model.traits.UnitTypeTrait;
43	import software.amazon.smithy.utils.AbstractCodeWriter;
44	import software.amazon.smithy.utils.FunctionalUtils;
45	import software.amazon.smithy.utils.ListUtils;
46	import software.amazon.smithy.utils.Pair;
47	import software.amazon.smithy.utils.SimpleCodeWriter;
48	import software.amazon.smithy.utils.SmithyBuilder;
49	import software.amazon.smithy.utils.StringUtils;
50	
51	/**
52	 * Serializes a {@link Model} into a set of Smithy IDL files.
53	 */
54	public final class SmithyIdlModelSerializer {
55	    private static final String DEFAULT_INLINE_INPUT_SUFFIX = "Input";
56	    private static final String DEFAULT_INLINE_OUTPUT_SUFFIX = "Output";
57	
58	    private final Predicate<String> metadataFilter;
59	    private final Predicate<Shape> shapeFilter;
60	    private final Predicate<Trait> traitFilter;
61	    private final Function<Shape, Path> shapePlacer;
62	    private final Path basePath;
63	    private final SmithyIdlComponentOrder componentOrder;
64	    private final String inlineInputSuffix;
65	    private final String inlineOutputSuffix;
66	    private final boolean inferInlineIoSuffixes;
67	    private final boolean shouldCoerceInlineIo;
68	
69	    /**
70	     * Trait serialization features.
71	     */
72	    private enum TraitFeature {
73	        /** Inline documentation traits with other traits as opposed to using /// syntax. */
74	        NO_SPECIAL_DOCS_SYNTAX,
75	
76	        /** Serializing a member, so special default syntax can be used. */
77	        MEMBER;
78	
79	        /**
80	         * Checks if the current enum value is present in an array of enum values.
81	         *
82	         * @param haystack Array of enums to check.
83	         * @return Returns true if this enum is found in the array.
84	         */
85	        boolean hasFeature(TraitFeature[] haystack) {
86	            for (TraitFeature test : haystack) {
87	                if (test == this) {
88	                    return true;
89	                }
90	            }
91	            return false;
92	        }
93	    }
94	
95	    private SmithyIdlModelSerializer(Builder builder) {
96	        metadataFilter = builder.metadataFilter;
97	        // If prelude serializing has been enabled, only use the given shape filter.
98	        if (builder.serializePrelude) {
99	            shapeFilter = builder.shapeFilter;
100	            // Default to using the given shape filter and filtering prelude shapes.
101	        } else {
102	            shapeFilter = builder.shapeFilter.and(FunctionalUtils.not(Prelude::isPreludeShape));
103	        }
104	        // Never serialize synthetic traits.
105	        traitFilter = builder.traitFilter.and(FunctionalUtils.not(Trait::isSynthetic));
106	        basePath = builder.basePath;
107	        if (basePath != null) {
108	            Function<Shape, Path> placer = builder.shapePlacer;
109	            shapePlacer = shape -> basePath.resolve(placer.apply(shape));
110	        } else {
111	            shapePlacer = builder.shapePlacer;
112	        }
113	        componentOrder = builder.componentOrder;
114	        inlineInputSuffix = builder.inlineInputSuffix;
115	        inlineOutputSuffix = builder.inlineOutputSuffix;
116	        shouldCoerceInlineIo = builder.shouldCoerceInlineIo;
117	        // Force inferring suffixes on if coercion is on.
118	        if (shouldCoerceInlineIo) {
119	            inferInlineIoSuffixes = true;
120	        } else {
121	            inferInlineIoSuffixes = builder.inferInlineIoSuffixes;
122	        }
123	    }
124	
125	    /**
126	     * Serializes a {@link Model} into a set of Smithy IDL files.
127	     *
128	     * <p>The output is a mapping
129	     *
130	     * <p>By default the paths are relative paths where each namespace is given its own file in the form
131	     * "namespace.smithy". This is configurable via the shape placer, which can place shapes into absolute
132	     * paths.
133	     *
134	     * <p>If the model contains no shapes, or all shapes are filtered out, then a single path "metadata.smithy"
135	     * will be present. This will contain only any defined metadata.
136	     *
137	     * @param model The model to serialize.
138	     * @return A map of (possibly relative) file paths to Smithy IDL strings.
139	     */
140	    public Map<Path, String> serialize(Model model) {
141	        Map<Path, String> result = model.shapes()
142	                .filter(FunctionalUtils.not(Shape::isMemberShape))
143	                .filter(shapeFilter)
144	                .collect(Collectors.groupingBy(shapePlacer))
145	                .entrySet()
146	                .stream()
147	                .collect(Collectors.toMap(Map.Entry::getKey, entry -> serialize(model, entry.getValue())));
148	        // If there is no metadata, do not create metadata file
149	        if (model.getMetadata().isEmpty()) {
150	            return result;
151	        }
152	
153	        // Add metadata file to the list of output files
154	        Path metadataPath = Paths.get("metadata.smithy");
155	        if (basePath != null) {
156	            metadataPath = basePath.resolve(metadataPath);
157	        }
158	        if (result.isEmpty()) {
159	            return Collections.singletonMap(metadataPath,
160	                    serializeHeader(
161	                            model,
162	                            null,
163	                            Collections.emptySet(),
164	                            inlineInputSuffix,
165	                            inlineOutputSuffix,
166	                            true));
167	        } else {
168	            result.put(metadataPath,
169	                    serializeHeader(
170	                            model,
171	                            null,
172	                            Collections.emptySet(),
173	                            inlineInputSuffix,
174	                            inlineOutputSuffix,
175	                            true));
176	        }
177	        return result;
178	    }
179	
180	    private String serialize(Model fullModel, Collection<Shape> shapes) {
181	        Set<String> namespaces = shapes.stream()
182	                .map(shape -> shape.getId().getNamespace())
183	                .collect(Collectors.toSet());
184	        if (namespaces.size() != 1) {
185	            throw new RuntimeException("All shapes in a single file must share a namespace.");
186	        }
187	
188	        // There should only be one namespace at this point, so grab it.
189	        String namespace = namespaces.iterator().next();
190	        SmithyCodeWriter codeWriter = new SmithyCodeWriter(namespace, fullModel);
191	        NodeSerializer nodeSerializer = new NodeSerializer(codeWriter, fullModel);
192	
193	        Pair<String, String> inlineSuffixes = determineInlineSuffixes(fullModel, shapes);
194	        Set<ShapeId> inlineableShapes = getInlineableShapes(
195	                fullModel,
196	                shapes,
197	                inlineSuffixes.getLeft(),
198	                inlineSuffixes.getRight());
199	        ShapeSerializer shapeSerializer = new ShapeSerializer(
200	                codeWriter,
201	                nodeSerializer,
202	                traitFilter,
203	                fullModel,
204	                inlineableShapes,
205	                componentOrder);
206	        Comparator<Shape> comparator = componentOrder.shapeComparator();
207	        shapes.stream()
208	                .filter(FunctionalUtils.not(Shape::isMemberShape))
209	                .filter(shape -> !inlineableShapes.contains(shape.getId()))
210	                .sorted(comparator)
211	                .forEach(shape -> shape.accept(shapeSerializer));
212	
213	        String header = serializeHeader(
214	                fullModel,
215	                namespace,
216	                shapes,
217	                inlineSuffixes.getLeft(),
218	                inlineSuffixes.getRight(),
219	                false);
220	        return header + codeWriter;
221	    }
222	
223	    private Set<ShapeId> getInlineableShapes(
224	            Model fullModel,
225	            Collection<Shape> shapes,
226	            String inputSuffix,
227	            String outputSuffix
228	    ) {
229	        OperationIndex operationIndex = OperationIndex.of(fullModel);
230	        Set<ShapeId> inlineableShapes = new HashSet<>();
231	        for (Shape shape : shapes) {
232	            if (!shape.isOperationShape()) {
233	                continue;
234	            }
235	            OperationShape operation = shape.asOperationShape().get();
236	            if (!operation.getInputShape().equals(UnitTypeTrait.UNIT)) {
237	                Shape inputShape = fullModel.expectShape(operation.getInputShape());
238	                if (shapes.contains(inputShape) && shouldInlineInputShape(operationIndex, inputShape)
239	                        && inputShape.getId().getName().equals(operation.getId().getName() + inputSuffix)) {
240	                    inlineableShapes.add(operation.getInputShape());
241	                }
242	            }
243	            if (!operation.getOutputShape().equals(UnitTypeTrait.UNIT)) {
244	                Shape outputShape = fullModel.expectShape(operation.getOutputShape());
245	                if (shapes.contains(outputShape) && shouldInlineOutputShape(operationIndex, outputShape)
246	                        && outputShape.getId().getName().equals(operation.getId().getName() + outputSuffix)) {
247	                    inlineableShapes.add(operation.getOutputShape());
248	                }
249	            }
250	        }
251	        return inlineableShapes;
252	    }
253	
254	    private boolean shouldInlineInputShape(OperationIndex operationIndex, Shape target) {
255	        // Only allow coercion if the shape is only used as one input.
256	        return target.hasTrait(InputTrait.ID)
257	                || (shouldCoerceInlineIo && operationIndex.getInputBindings(target).size() == 1);
258	    }
259	
260	    private boolean shouldInlineOutputShape(OperationIndex operationIndex, Shape target) {
261	        // Only allow coercion if the shape is only used as one output.
262	        return target.hasTrait(OutputTrait.ID)
263	                || (shouldCoerceInlineIo && operationIndex.getOutputBindings(target).size() == 1);
264	    }
265	
266	    private Pair<String, String> determineInlineSuffixes(Model fullModel, Collection<Shape> shapes) {
267	        if (!inferInlineIoSuffixes) {
268	            return Pair.of(inlineInputSuffix, inlineOutputSuffix);
269	        }
270	
271	        Map<String, Integer> inputSuffixes = new LinkedHashMap<>();
272	        Map<String, Integer> outputSuffixes = new LinkedHashMap<>();
273	        for (Shape shape : shapes) {
274	            if (!shape.isOperationShape()) {
275	                continue;
276	            }
277	            OperationShape operation = shape.asOperationShape().get();
278	
279	            StructureShape input = fullModel.expectShape(operation.getInputShape(), StructureShape.class);
280	            StructureShape output = fullModel.expectShape(operation.getOutputShape(), StructureShape.class);
281	
282	            if (shapes.contains(input) && input.getId().getName().startsWith(operation.getId().getName())) {
283	                String inputSuffix = input.getId().getName().substring(operation.getId().getName().length());
284	                int inputCount = inputSuffixes.getOrDefault(inputSuffix, 0);
285	                inputSuffixes.put(inputSuffix, ++inputCount);
286	            }
287	
288	            if (shapes.contains(output) && output.getId().getName().startsWith(operation.getId().getName())) {
289	                String outputSuffix = output.getId().getName().substring(operation.getId().getName().length());
290	                int outputCount = outputSuffixes.getOrDefault(outputSuffix, 0);
291	                outputSuffixes.put(outputSuffix, ++outputCount);
292	            }
293	        }
294	
295	        String inputSuffix = inputSuffixes.entrySet()
296	                .stream()
297	                .max(Map.Entry.comparingByValue())
298	                .map(Map.Entry::getKey)
299	                .orElse(inlineInputSuffix);
300	        String outputSuffix = outputSuffixes.entrySet()
301	                .stream()
302	                .max(Map.Entry.comparingByValue())
303	                .map(Map.Entry::getKey)
304	                .orElse(inlineOutputSuffix);
305	        return Pair.of(inputSuffix, outputSuffix);
306	    }
307	
308	    private String serializeHeader(
309	            Model fullModel,
310	            String namespace,
311	            Collection<Shape> shapes,
312	            String inputSuffix,
313	            String outputSuffix,
314	            boolean addMetadata
315	    ) {
316	        SmithyCodeWriter codeWriter = new SmithyCodeWriter(null, fullModel);
317	        codeWriter.write("$$version: \"$L\"", Model.MODEL_VERSION);
318	
319	        if (shapes.stream().anyMatch(Shape::isOperationShape)) {
320	            if (!inputSuffix.equals(DEFAULT_INLINE_INPUT_SUFFIX)) {
321	                codeWriter.write("$$operationInputSuffix: $S", inputSuffix);
322	            }
323	
324	            if (!outputSuffix.equals(DEFAULT_INLINE_OUTPUT_SUFFIX)) {
325	                codeWriter.write("$$operationOutputSuffix: $S", outputSuffix);
326	            }
327	        }
328	
329	        codeWriter.write("");
330	
331	        if (addMetadata) {
332	            NodeSerializer nodeSerializer = new NodeSerializer(codeWriter, fullModel);
333	            Comparator<Map.Entry<String, Node>> comparator = componentOrder.metadataComparator();
334	            fullModel.getMetadata()
335	                    .entrySet()
336	                    .stream()
337	                    .filter(entry -> metadataFilter.test(entry.getKey()))
338	                    .sorted(comparator)
339	                    .forEach(entry -> {
340	                        codeWriter.trimTrailingSpaces(false)
341	                                .writeInline("metadata $K = ", entry.getKey())
342	                                .trimTrailingSpaces();
343	                        nodeSerializer.serialize(entry.getValue());
344	                        codeWriter.write("");
345	                    });
346	        }
347	
348	        if (namespace != null) {
349	            codeWriter.write("namespace $L", namespace)
350	                    .write("")
351	                    // We want the extra blank line to separate the header and the model contents.
352	                    .trimBlankLines(-1);
353	        }
354	
355	        return codeWriter.toString();
356	    }
