921	    /**
922	     * Serializes nodes into the Smithy IDL format.
923	     */
924	    private static final class NodeSerializer {
925	        private final SmithyCodeWriter codeWriter;
926	        private final Model model;
927	
928	        NodeSerializer(SmithyCodeWriter codeWriter, Model model) {
929	            this.codeWriter = codeWriter;
930	            this.model = model;
931	        }
932	
933	        /**
934	         * Serialize a node into the Smithy IDL format.
935	         *
936	         * @param node The node to serialize.
937	         */
938	        private void serialize(Node node) {
939	            serialize(node, null);
940	        }
941	
942	        /**
943	         * Serialize a node into the Smithy IDL format.
944	         *
945	         * <p>This uses the given shape to influence serialization. For example, a string shape marked with the idRef
946	         * trait will be serialized as a shape id rather than a string.
947	         *
948	         * @param node The node to serialize.
949	         * @param shape The shape of the node.
950	         */
951	        private void serialize(Node node, Shape shape) {
952	            // ShapeIds are represented differently than strings, so if a shape looks like it's
953	            // representing a shapeId we need to serialize it without quotes. However, if the
954	            // shape ID doesn't resolve to a shape in the model, it must be quoted to ensure
955	            // valid IDL output (the target may not exist when @idRef failWhenMissing is false).
956	            if (isShapeId(shape) && isResolvableShapeId(node)) {
957	                serializeShapeId(node.expectStringNode());
958	                return;
959	            }
960	
961	            if (shape != null && shape.isMemberShape()) {
962	                shape = model.expectShape(shape.asMemberShape().get().getTarget());
963	            }
964	
965	            if (node.isStringNode()) {
966	                serializeString(node.expectStringNode());
967	            } else if (node.isNumberNode()) {
968	                serializeNumber(node.expectNumberNode());
969	            } else if (node.isBooleanNode()) {
970	                serializeBoolean(node.expectBooleanNode());
971	            } else if (node.isNullNode()) {
972	                serializeNull();
973	            } else if (node.isArrayNode()) {
974	                serializeArray(node.expectArrayNode(), shape);
975	            } else if (node.isObjectNode()) {
976	                serializeObject(node.expectObjectNode(), shape);
977	            }
978	        }
979	
980	        private boolean isShapeId(Shape shape) {
981	            if (shape == null) {
982	                return false;
983	            }
984	            return shape.getMemberTrait(model, IdRefTrait.class).isPresent();
985	        }
986	
987	        private boolean isResolvableShapeId(Node node) {
988	            if (!node.isStringNode()) {
989	                return false;
990	            }
991	            try {
992	                ShapeId id = ShapeId.from(node.expectStringNode().getValue());
993	                return model.getShape(id).isPresent();
994	            } catch (ShapeIdSyntaxException e) {
995	                return false;
996	            }
997	        }
998	
999	        private void serializeString(StringNode node) {
1000	            codeWriter.writeInline("$S", node.getValue());
1001	        }
1002	
1003	        private void serializeShapeId(StringNode node) {
1004	            codeWriter.writeInline("$I", node.getValue());
1005	        }
1006	
1007	        private void serializeNumber(NumberNode node) {
1008	            codeWriter.writeInline("$L", node.getValue());
1009	        }
1010	
1011	        private void serializeBoolean(BooleanNode node) {
1012	            codeWriter.writeInline(String.valueOf(node.getValue()));
1013	        }
1014	
1015	        private void serializeNull() {
1016	            codeWriter.writeInline("null");
1017	        }
1018	
1019	        private void serializeArray(ArrayNode node, Shape shape) {
1020	            if (node.isEmpty()) {
1021	                codeWriter.writeInline("[]");
1022	                return;
1023	            }
1024	
1025	            codeWriter.openBlockInline("[");
1026	
1027	            // If it's not a collection shape, it'll be a document shape or null
1028	            Shape member = shape;
1029	            if (shape instanceof CollectionShape) {
1030	                member = ((CollectionShape) shape).getMember();
1031	            }
1032	
1033	            for (Node element : node.getElements()) {
1034	                // Elements will be written inline to enable them being written as values.
1035	                // So here we need to ensure that they're written on a new line that's properly indented.
1036	                codeWriter.write("");
1037	                codeWriter.writeIndent();
1038	                serialize(element, member);
1039	            }
1040	            codeWriter.write("");
1041	
1042	            // We want to make sure to close without inserting a newline, as this could itself be a list element
1043	            //or an object value.
1044	            codeWriter.closeBlockWithoutNewline("]");
1045	        }
1046	
1047	        private void serializeObject(ObjectNode node, Shape shape) {
1048	            if (node.isEmpty()) {
1049	                codeWriter.writeInline("{}");
1050	                return;
1051	            }
1052	
1053	            codeWriter.openBlockInline("{");
1054	            serializeKeyValuePairs(node, shape);
1055	            codeWriter.closeBlockWithoutNewline("}");
1056	        }
1057	
1058	        /**
1059	         * Serialize an object node without the surrounding brackets.
1060	         *
1061	         * <p>This is mainly useful for serializing trait value nodes.
1062	         *
1063	         * @param node The node to serialize.
1064	         * @param shape The shape of the node.
1065	         */
1066	        private void serializeKeyValuePairs(ObjectNode node, Shape shape) {
1067	            if (node.isEmpty()) {
1068	                return;
1069	            }
1070	
1071	            // If we're looking at a structure or union shape, we'll need to get the member shape based on the
1072	            // node key. Here we pre-compute a mapping, so we don't have to traverse the member list every time.
1073	            Map<String, MemberShape> members;
1074	            if (shape == null) {
1075	                members = Collections.emptyMap();
1076	            } else {
1077	                members = shape.members()
1078	                        .stream()
1079	                        .collect(Collectors.toMap(MemberShape::getMemberName, Function.identity()));
1080	            }
1081	
1082	            node.getMembers().forEach((name, value) -> {
1083	                // Try to find the member shape.
1084	                Shape member;
1085	                if (shape != null && shape.isMapShape()) {
1086	                    // For maps the value member will always be the same.
1087	                    member = shape.asMapShape().get().getValue();
1088	                } else if (shape instanceof StructureShape || shape instanceof UnionShape) {
1089	                    member = members.get(name.getValue());
1090	                } else {
1091	                    // At this point the shape is either null or a document shape.
1092	                    member = shape;
1093	                }
1094	
1095	                codeWriter.writeInline("\n$K: ", name.getValue());
1096	                serialize(value, member);
1097	            });
1098	            codeWriter.write("");
1099	        }
1100	    }
1101	
1102	    /**
1103	     * Extension of {@link SimpleCodeWriter} that provides additional convenience methods.
1104	     *
1105	     * <p>Provides a built-in $I formatter that formats shape ids, automatically trimming namespace where possible.
1106	     */
1107	    private static final class SmithyCodeWriter extends SimpleCodeWriter {
1108	        private static final Pattern UNQUOTED_KEY_STRING = Pattern.compile("[a-zA-Z_][a-zA-Z_0-9]*");
1109	        private final String namespace;
1110	        private final Model model;
1111	        private final Set<ShapeId> imports;
1112	
1113	        SmithyCodeWriter(String namespace, Model model) {
1114	            super();
1115	            this.namespace = namespace;
1116	            this.model = model;
1117	            this.imports = new HashSet<>();
1118	            trimTrailingSpaces();
1119	            trimBlankLines();
1120	            putFormatter('I', (s, i) -> formatShapeId(s));
1121	            putFormatter('K', this::optionallyQuoteKey);
1122	        }
1123	
1124	        /**
1125	         * Opens a block without writing indentation whitespace or inserting a newline.
1126	         */
1127	        private SmithyCodeWriter openBlockInline(String content, Object... args) {
1128	            writeInline(content, args).indent();
1129	            return this;
1130	        }
1131	
1132	        /**
1133	         * Closes a block without inserting a newline.
1134	         */
1135	        private SmithyCodeWriter closeBlockWithoutNewline(String content, Object... args) {
1136	            setNewline("");
1137	            closeBlock(content, args);
1138	            setNewline("\n");
1139	            return this;
1140	        }
1141	
1142	        /**
1143	         * Writes an empty line that contains only indentation appropriate to the current indentation level.
1144	         *
1145	         * <p> This does not insert a trailing newline.
1146	         */
1147	        private SmithyCodeWriter writeIndent() {
1148	            setNewline("");
1149	            // We explicitly want the trailing spaces, so disable trimming for this call.
1150	            trimTrailingSpaces(false);
1151	            write("");
1152	            trimTrailingSpaces();
1153	            setNewline("\n");
1154	            return this;
1155	        }
1156	
1157	        private String formatShapeId(Object value) {
1158	            if (value == null) {
1159	                return "";
1160	            }
1161	            ShapeId shapeId = ShapeId.from(String.valueOf(value));
1162	            if (!shouldWriteNamespace(shapeId)) {
1163	                return shapeId.asRelativeReference();
1164	            }
1165	            return shapeId.toString();
1166	        }
1167	
1168	        private boolean shouldWriteNamespace(ShapeId shapeId) {
1169	            if (shapeId.getNamespace().equals(namespace)) {
1170	                return false;
1171	            }
1172	            if (Prelude.isPublicPreludeShape(shapeId)) {
1173	                return conflictsWithLocalNamespace(shapeId);
1174	            }
1175	            if (shouldImport(shapeId)) {
1176	                imports.add(shapeId.withoutMember());
1177	            }
1178	            return !imports.contains(shapeId);
1179	        }
1180	
1181	        private boolean conflictsWithLocalNamespace(ShapeId shapeId) {
1182	            return model.getShape(ShapeId.fromParts(namespace, shapeId.getName())).isPresent();
1183	        }
1184	
1185	        private boolean shouldImport(ShapeId shapeId) {
1186	            return !conflictsWithLocalNamespace(shapeId)
1187	                    // It's easier to simply never import something that conflicts with the prelude, because
1188	                    // if we did then we'd have to somehow handle rewriting all existing references to the
1189	                    // prelude shape that it conflicts with.
1190	                    && !conflictsWithPreludeNamespace(shapeId)
1191	                    && !conflictsWithImports(shapeId);
1192	
1193	        }
1194	
1195	        private boolean conflictsWithPreludeNamespace(ShapeId shapeId) {
1196	            return Prelude.isPublicPreludeShape(ShapeId.fromParts(Prelude.NAMESPACE, shapeId.getName()));
1197	        }
1198	
1199	        private boolean conflictsWithImports(ShapeId shapeId) {
1200	            return imports.stream().anyMatch(importId -> importId.getName().equals(shapeId.getName()));
1201	        }
1202	
1203	        /**
1204	         * Writes a possibly-empty list where each element is a shape id.
1205	         *
1206	         * <p>If the list is empty, nothing is written.
1207	         */
1208	        private SmithyCodeWriter writeOptionalIdList(String textBeforeList, Collection<ShapeId> shapeIds) {
1209	            if (shapeIds.isEmpty()) {
1210	                return this;
1211	            }
1212	
1213	            openBlock("$L: [", textBeforeList);
1214	            shapeIds.stream().sorted().forEach(shapeId -> write("$I", shapeId));
1215	            closeBlock("]");
1216	
1217	            return this;
1218	        }
1219	
1220	        /**
1221	         * Formatter that quotes (and escapes) a string unless it's a valid object key string.
1222	         */
1223	        private String optionallyQuoteKey(Object key, String indent) {
1224	            String formatted = AbstractCodeWriter.formatLiteral(key);
1225	            if (UNQUOTED_KEY_STRING.matcher(formatted).matches()) {
1226	                return formatted;
1227	            }
1228	            return StringUtils.escapeJavaString(formatted, indent);
1229	        }
1230	
1231	        @Override
1232	        public String toString() {
1233	            String contents = StringUtils.stripStart(super.toString(), null);
1234	            if (imports.isEmpty()) {
1235	                return contents;
1236	            }
1237	            String importString = imports.stream()
1238	                    .sorted()
1239	                    .map(shapeId -> String.format("use %s", shapeId.toString()))
1240	                    .collect(Collectors.joining("\n"));
1241	            return importString + "\n\n" + contents;
1242	        }
1243	    }
1244	}
