                .id("smithy.example#Set")
                .member(ShapeId.from("smithy.api#String"))
                .build();
        Model model = Model.assembler().addShape(set).assemble().unwrap();
        SmithyIdlModelSerializer serializer = SmithyIdlModelSerializer.builder().build();
