    @Test
    public void sortsAlphabetically() {
        URL before = getClass().getResource("idl-serialization/alphabetical/before.smithy");
        URL after = getClass().getResource("idl-serialization/alphabetical/after.smithy");
        URL metadata = getClass().getResource("idl-serialization/alphabetical/metadata.smithy");

        Model model = Model.assembler().addImport(before).assemble().unwrap();
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .componentOrder(SmithyIdlComponentOrder.ALPHA_NUMERIC)
                .build()
                .serialize(model);

        String modelResult = reserialized.get(Paths.get("com.example.smithy")).replace("\r\n", "\n");
        String metadataResult = reserialized.get(Paths.get("metadata.smithy")).replace("\r\n", "\n");

        assertThat(modelResult, equalTo(IoUtils.readUtf8Url(after).replace("\r\n", "\n")));
        assertThat(metadataResult, equalTo(IoUtils.readUtf8Url(metadata).replace("\r\n", "\n")));
    }

    @Test
    public void handlesEnumMixins() {
        URL resource = getClass().getResource("idl-serialization/enum-mixin-input.smithy");
        Model model = Model.assembler().addImport(resource).assemble().unwrap();
        Map<Path, String> serialized = SmithyIdlModelSerializer.builder().build().serialize(model);

        if (serialized.size() != 1) {
            throw new RuntimeException("Exactly one smithy file should be output for generated tests.");
        }

        String expectedOutput = IoUtils.readUtf8Resource(getClass(), "idl-serialization/enum-mixin-output.smithy")
                .replaceAll("\\R", "\n");
        String serializedString = serialized.entrySet().iterator().next().getValue();
        assertEquals(expectedOutput, serializedString);
    }

    @Test
    public void handlesCustomInlineSuffixes() {
        URL resource = getClass().getResource("idl-serialization/custom-inline-io.smithy");
        Model model = Model.assembler().addImport(resource).assemble().unwrap();

        Assertions.assertTrue(model.getShape(ShapeId.from("com.example#InlineOperationRequest")).isPresent());
        Assertions.assertTrue(model.getShape(ShapeId.from("com.example#InlineOperationResponse")).isPresent());

        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .inlineInputSuffix("Request")
                .inlineOutputSuffix("Response")
                .build()
                .serialize(model);
        String modelResult = reserialized.values().iterator().next().replace("\r\n", "\n");

        assertThat(modelResult, equalTo(IoUtils.readUtf8Url(resource).replace("\r\n", "\n")));
    }

    @Test
    public void canInferInlineSuffixes() {
        Map<Path, URL> resources = MapUtils.of(
                Paths.get("default.smithy"),
                getClass().getResource("idl-serialization/inferred-io/default.smithy"),
                Paths.get("main.smithy"),
                getClass().getResource("idl-serialization/inferred-io/main.smithy"),
                Paths.get("mixed.smithy"),
                getClass().getResource("idl-serialization/inferred-io/mixed.smithy"),
                Paths.get("shared.smithy"),
                getClass().getResource("idl-serialization/inferred-io/shared.smithy"));
        ModelAssembler assembler = Model.assembler();
        resources.values().forEach(assembler::addImport);
        Model model = assembler.assemble().unwrap();

        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .shapePlacer(s -> Paths.get(s.getSourceLocation().getFilename()).getFileName())
                .inferInlineIoSuffixes(true)
                .build()
                .serialize(model);

        assertThat(reserialized.size(), equalTo(resources.size()));
        for (Map.Entry<Path, String> entry : reserialized.entrySet()) {
            Path path = entry.getKey();
            String actual = entry.getValue().replace("\r\n", "\n");
            String expected = IoUtils.readUtf8Url(resources.get(path)).replace("\r\n", "\n");
            assertThat(actual, equalTo(expected));
        }
    }

    @Test
    public void coercesInlineIO() {
        Model before = Model.assembler()
                .addImport(getClass().getResource("idl-serialization/coerced-io/before.smithy"))
                .assemble()
                .unwrap();

        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .coerceInlineIo(true)
                .build()
                .serialize(before);
        String modelResult = reserialized.values().iterator().next().replace("\r\n", "\n");

        String expected = IoUtils.readUtf8Url(getClass().getResource("idl-serialization/coerced-io/after.smithy"))
                .replace("\r\n", "\n");
        assertEquals(expected, modelResult);
    }

    @Test
    public void docsNotDuplicateDocsForDynamicDocTrait() {
        Model model = Model.builder()
                .addShape(StructureShape.builder()
                        .id("test#test")
                        .addTrait(
                                new DynamicTrait(
                                        ShapeId.from("smithy.api#documentation"),
                                        Node.from("hello")))
                        .build())
                .build();
        Map<Path, String> serialized = SmithyIdlModelSerializer.builder().build().serialize(model);
        String modelResult = serialized.values().iterator().next().replace("\r\n", "\n");

        // IDL serializer will serialize docs with the special syntax, so we can check that it does not also add
        // the doc trait itself
        assertFalse(modelResult.contains("@documentation"));
        assertTrue(modelResult.contains("/// hello"));
    }

    @Test
    public void customShapeComparator() {
        // Create a model with shapes in alphanumeric order
        Model model = Model.assembler()
                .addImport(getClass().getResource("idl-serialization/alphabetical/after.smithy"))
                .assemble()
                .unwrap();
        // Use a custom comparator that reverses the order
        Comparator<Shape> reversed = Comparator.comparing(Shape::getId).reversed();
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .shapeComparator(reversed)
                .build()
                .serialize(model);

        String modelResult = reserialized.get(Paths.get("com.example.smithy")).replace("\r\n", "\n");

        // With a reversed comparator, shapes should appear in reverse alphabetical order
        // The last shape alphabetically (StructureZ) should be first
        assertThat(modelResult.indexOf("StructureZ"), not(-1));
        assertThat(modelResult.indexOf("StructureA"), not(-1));
        assertThat(modelResult.indexOf("StructureZ") < modelResult.indexOf("StructureA"), is(true));
    }

    @Test
    public void customShapeComparatorPutsSpecificShapeLast() {
        Model model = Model.assembler()
                .addImport(getClass().getResource("idl-serialization/alphabetical/after.smithy"))
                .assemble()
                .unwrap();
        // Custom comparator that puts a specific shape last
        ShapeId lastShapeId = ShapeId.from("com.example#StructureZ");
        Comparator<Shape> custom = Comparator.comparing(
                (Shape s) -> s.getId().equals(lastShapeId) ? 1 : 0)
                .thenComparing(Shape::getId);
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .shapeComparator(custom)
                .build()
                .serialize(model);

        String modelResult = reserialized.get(Paths.get("com.example.smithy")).replace("\r\n", "\n");

        // StructureZ should appear last
        assertThat(modelResult.trim().endsWith("StructureZ {}"), is(true));
    }

    @Test
    public void customMetadataComparator() {
        Model model = Model.assembler()
                .putMetadata("z_metadata", StringNode.from("z"))
                .putMetadata("a_metadata", StringNode.from("a"))
                .assemble()
                .unwrap();
        // Custom comparator that reverses metadata order
        Comparator<Map.Entry<String, Node>> reversed = Map.Entry.<String, Node>comparingByKey().reversed();
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .metadataComparator(reversed)
                .build()
                .serialize(model);

        String metaResult = reserialized.get(Paths.get("metadata.smithy")).replace("\r\n", "\n");

        // z_metadata should appear before a_metadata
        assertThat(metaResult.indexOf("z_metadata") < metaResult.indexOf("a_metadata"), is(true));
    }

    @Test
    public void customTraitComparator() {
        String modelString = "$version: \"2.0\"\n"
                + "namespace com.example\n"
                + "@length(min: 1, max: 100)\n"
                + "@documentation(\"test\")\n"
                + "string MyString\n";
        Model model = Model.assembler()
                .addUnparsedModel("test.smithy", modelString)
                .assemble()
                .unwrap();
        // Custom comparator that reverses trait order
        Comparator<Trait> reversed = Comparator.<Trait, ShapeId>comparing(Trait::toShapeId).reversed();
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .traitComparator(reversed)
                .build()
                .serialize(model);

        String modelResult = reserialized.get(Paths.get("com.example.smithy")).replace("\r\n", "\n");

        // length should appear before documentation (due to reverse order)
        assertThat(modelResult.indexOf("@length") < modelResult.indexOf("@documentation"), is(true));
    }

    @Test
    public void unresolvableIdRefSerializedAsQuotedString() {
        String stringModel = "$version: \"2.0\"\n"
                + "namespace ns.foo\n"
                + "@trait\n"
                + "structure myTrait {\n"
                + "    ref: MyRef\n"
                + "}\n"
                + "@idRef\n"
                + "string MyRef\n"
                + "@myTrait(ref: \"ns.foo#DoesNotExist\")\n"
                + "string MyTarget\n";
        Model model = Model.assembler().addUnparsedModel("test.smithy", stringModel).assemble().unwrap();
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder().build().serialize(model);
        String modelResult = reserialized.get(Paths.get("ns.foo.smithy"));

        // Re-assemble the serialized output. On unfixed code, this fails because the
        // serializer renders the unresolvable idRef as a bare shape ID (DoesNotExist)
        // which the parser rejects as a syntactic shape ID that doesn't resolve.
        Model model2 = Model.assembler().addUnparsedModel("test.smithy", modelResult).assemble().unwrap();
        assertThat(model2, equalTo(model));
    }
}

