    @Test
    public void customShapeComparator() {
        // Use a model with multiple shapes: Abc, Def, Hij (in original order)
        Model model = Model.assembler()
                .addImport(getClass().getResource("idl-serialization/alphabetical/before.smithy"))
                .assemble()
                .unwrap();
        // Use a custom comparator that reverses the order (Hij should come first)
        Comparator<Shape> reversed = Comparator.comparing(Shape::getId).reversed();
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .shapeComparator(reversed)
                .build()
                .serialize(model);

        String modelResult = reserialized.get(Paths.get("com.example.smithy")).replace("\r\n", "\n");

        // With reversed comparator, Hij (service) should appear before Abc (structure)
        assertThat(modelResult.indexOf("Hij") < modelResult.indexOf("Abc"), is(true));
    }

    @Test
    public void customShapeComparatorPutsSpecificShapeLast() {
        Model model = Model.assembler()
                .addImport(getClass().getResource("idl-serialization/alphabetical/before.smithy"))
                .assemble()
                .unwrap();
        // Custom comparator that puts Abc last, all others in normal order
        ShapeId lastShapeId = ShapeId.from("com.example#Abc");
        Comparator<Shape> custom = Comparator.comparing(
                (Shape s) -> s.getId().equals(lastShapeId) ? 1 : 0)
                .thenComparing(Shape::getId);
        Map<Path, String> reserialized = SmithyIdlModelSerializer.builder()
                .shapeComparator(custom)
                .build()
                .serialize(model);

        String modelResult = reserialized.get(Paths.get("com.example.smithy")).replace("\r\n", "\n");

        // Abc should appear last (after Def which is the other non-service shape)
        assertTrue(modelResult.indexOf("Abc") > modelResult.indexOf("Def"));
    }

